            codingExamples: "import numpy as np\n\n# Power iteration for dominant eigenvector\ndef power_iteration(A: np.ndarray, n_iter: int = 100) -> tuple:\n    n = A.shape[0]\n    v = np.random.randn(n)\n    v = v / np.linalg.norm(v)\n    for _ in range(n_iter):\n        Av = A @ v\n        eigenvalue = v @ Av\n        v = Av / np.linalg.norm(Av)\n    return eigenvalue, v\n\n# PCA via SVD (more stable than eigendecomposition of covariance)\nX = np.random.randn(100, 5)\nX_centered = X - np.mean(X, axis=0)\nU, S, Vt = np.linalg.svd(X_centered, full_matrices=False)\n\n# Principal components are rows of Vt\nexplained_ratio = S**2 / np.sum(S**2)\nprint(f'Explained variance ratio: {explained_ratio}')\n\n# Project data onto top-2 PCs\nX_pca = X_centered @ Vt[:2, :].T",
