            codingExamples: "import numpy as np\nfrom sklearn.naive_bayes import GaussianNB, MultinomialNB, BernoulliNB\n\n# From-scratch Gaussian Naive Bayes for intuition\nclass GaussianNBScratch:\n    def fit(self, X: np.ndarray, y: np.ndarray):\n        self.classes = np.unique(y)\n        self.means = {}\n        self.stds = {}\n        self.priors = {}\n        for c in self.classes:\n            X_c = X[y == c]\n            self.means[c] = np.mean(X_c, axis=0)\n            self.stds[c] = np.std(X_c, axis=0) + 1e-9\n            self.priors[c] = len(X_c) / len(X)\n\n    def _gaussian_pdf(self, x, mean, std):\n        return np.exp(-0.5 * ((x - mean) / std) ** 2) / (std * np.sqrt(2 * np.pi))\n\n    def predict_proba(self, X):\n        probs = []\n        for x in X:\n            class_probs = []\n            for c in self.classes:\n                likelihood = np.prod(self._gaussian_pdf(x, self.means[c], self.stds[c]))\n                class_probs.append(likelihood * self.priors[c])\n            probs.append(np.array(class_probs) / sum(class_probs))\n        return np.array(probs)",
