            codingExamples: "import numpy as np\n\n# Ridge regression from scratch\nclass RidgeScratch:\n    def __init__(self, alpha=1.0):\n        self.alpha = alpha\n\n    def fit(self, X, y):\n        X_b = np.c_[np.ones((X.shape[0], 1)), X]\n        n_features = X_b.shape[1]\n        I = np.eye(n_features)\n        I[0, 0] = 0  # Don't regularize intercept\n        self.theta = np.linalg.inv(X_b.T @ X_b + self.alpha * I) @ X_b.T @ y\n        return self\n\n    def predict(self, X):\n        X_b = np.c_[np.ones((X.shape[0], 1)), X]\n        return X_b @ self.theta\n\n# Verify with sklearn\nfrom sklearn.linear_model import Ridge\nX = np.random.randn(50, 5)\ny = X @ np.array([1, -0.5, 2, 0, -1]) + np.random.randn(50) * 0.1\n\ncustom = RidgeScratch(alpha=1.0).fit(X, y)\nsklearn = Ridge(alpha=1.0).fit(X, y)\nprint(f'Custom vs sklearn coef diff: {np.abs(custom.theta[1:] - sklearn.coef_).mean():.6f}')",
