            intermediateExample: "import numpy as np\nfrom sklearn.linear_model import LassoCV, Lasso\nfrom sklearn.preprocessing import StandardScaler\n\n# Automated alpha selection with LassoCV\nX = np.random.randn(500, 50)\n# Only 5 relevant features\ny = X[:, :5] @ np.array([2, -1.5, 1, -0.5, 3]) + np.random.randn(500) * 0.5\n\nscaler = StandardScaler()\nX_scaled = scaler.fit_transform(X)\n\n# LassoCV tests many alphas automatically\nlasso_cv = LassoCV(cv=5, random_state=42, max_iter=10000)\nlasso_cv.fit(X_scaled, y)\n\nprint(f'Best alpha: {lasso_cv.alpha_:.4f}')\nprint(f'Non-zero coefficients: {np.sum(lasso_cv.coef_ != 0)}')\nprint(f'MSE: {lasso_cv.mse_path_.mean():.4f}')\n\n# Selected features\nselected = np.where(lasso_cv.coef_ != 0)[0]\nprint(f'Selected feature indices: {selected}')",
            productionExample: "import numpy as np\nfrom sklearn.linear_model import Lasso\nfrom sklearn.pipeline import Pipeline\nfrom sklearn.preprocessing import StandardScaler\n\nclass LassoFeatureSelector:\n    def __init__(self, alpha=0.01, max_features=None):\n        self.alpha = alpha\n        self.max_features = max_features\n\n    def fit(self, X, y):\n        self.scaler = StandardScaler()\n        X_scaled = self.scaler.fit_transform(X)\n        self.lasso = Lasso(alpha=self.alpha, max_iter=10000)\n        self.lasso.fit(X_scaled, y)\n        self.selected_features = np.where(self.lasso.coef_ != 0)[0]\n        if self.max_features:\n            # Keep only top features by absolute coefficient\n            top_idx = np.argsort(np.abs(self.lasso.coef_))[-self.max_features:]\n            self.selected_features = np.sort(top_idx)\n        return self\n\n    def transform(self, X):\n        return X[:, self.selected_features]\n\n    def get_selected_feature_names(self, feature_names):\n        return [feature_names[i] for i in self.selected_features]",
