            codingExamples: "import numpy as np\nfrom sklearn.linear_model import Lasso\n\n# Coordinate descent for Lasso (simplified)\ndef soft_threshold(x, lambda_):\n    \\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"Soft thresholding operator\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\",\n    return np.sign(x) * max(abs(x) - lambda_, 0)\n\ndef coordinate_descent_lasso(X, y, alpha, n_iter=1000, tol=1e-4):\n    n, p = X.shape\n    w = np.zeros(p)\n    residuals = y - X @ w\n    for _ in range(n_iter):\n        w_old = w.copy()\n        for j in range(p):\n            # Partial residual removing feature j\n            r_j = residuals + X[:, j] * w[j]\n            # Compute rho = X[:,j]^T r_j\n            rho = X[:, j] @ r_j\n            # Update w_j with soft threshold\n            w[j] = soft_threshold(rho, alpha) / (X[:, j] @ X[:, j])\n            # Update residuals\n            residuals = r_j - X[:, j] * w[j]\n        if np.sum((w - w_old)**2) < tol:\n            break\n    return w\n\n# Test\nX = np.random.randn(100, 10)\ny = X[:, 0] * 2 + X[:, 3] * (-1.5) + np.random.randn(100) * 0.1\nw_custom = coordinate_descent_lasso(X, y, alpha=0.1)\nw_sklearn = Lasso(alpha=0.1).fit(X, y).coef_\nprint('Custom:', np.round(w_custom, 4))\nprint('sklearn:', np.round(w_sklearn, 4))",
