            beginnerExample: "import numpy as np\nfrom sklearn.linear_model import LogisticRegression\nfrom sklearn.model_selection import train_test_split\n\n# Generate synthetic classification data\nnp.random.seed(42)\nX = np.random.randn(300, 2)\ny = (X[:, 0]**2 + X[:, 1] > 1).astype(int)\n\nX_train, X_test, y_train, y_test = train_test_split(X, y, test_size=0.2)\n\nmodel = LogisticRegression()\nmodel.fit(X_train, y_train)\n\nprint(f'Accuracy: {model.score(X_test, y_test):.3f}')\nprint(f'Coefficients: {model.coef_}')\nprint(f'Intercept: {model.intercept_:.3f}')\n\n# Predict probabilities\nprobs = model.predict_proba(X_test[:5])\nprint(f'Probabilities:\\\\\\\\\\\\\\\\n{probs}')",
            intermediateExample: "import numpy as np\nfrom sklearn.linear_model import LogisticRegression\nfrom sklearn.preprocessing import StandardScaler\nfrom sklearn.metrics import classification_report, roc_auc_score\n\n# Multi-class logistic regression (OvR)\nfrom sklearn.datasets import load_iris\niris = load_iris()\nX, y = iris.data, iris.target\n\nscaler = StandardScaler()\nX_scaled = scaler.fit_transform(X)\n\n# One-vs-Rest for multi-class\nmodel = LogisticRegression(multi_class='ovr', max_iter=1000)\nmodel.fit(X_scaled, y)\n\nprint(f'Accuracy: {model.score(X_scaled, y):.3f}')\nprint(f'\\\\\\\\\\\\\\\\nClassification Report:')\nprint(classification_report(y, model.predict(X_scaled), target_names=iris.target_names))\n\n# Probability calibration\nprobs = model.predict_proba(X_scaled[:5])\nprint(f'\\\\\\\\\\\\\\\\nClass probabilities (first 5):\\\\\\\\\\\\\\\\n{np.round(probs, 3)}')",
            productionExample: "import numpy as np\nfrom sklearn.linear_model import LogisticRegression\nfrom sklearn.pipeline import Pipeline\nfrom sklearn.preprocessing import StandardScaler\n\nclass LogisticRegressionModel:\n    def __init__(self, C=1.0, penalty='l2'):\n        self.pipeline = Pipeline([\n            ('scaler', StandardScaler()),\n            ('classifier', LogisticRegression(C=C, penalty=penalty, max_iter=1000))\n        ])\n\n    def fit(self, X, y):\n        self.pipeline.fit(X, y)\n        # Store feature importance\n        self.feature_importance = np.abs(\n            self.pipeline.named_steps['classifier'].coef_[0]\n        )\n        return self\n\n    def predict(self, X):\n        return self.pipeline.predict(X)\n\n    def predict_proba(self, X):\n        return self.pipeline.predict_proba(X)\n\n    def decision_function(self, X):\n        return self.pipeline.decision_function(X)\n\n    def top_features(self, feature_names, n=10):\n        idx = np.argsort(self.feature_importance)[-n:][::-1]\n        return [(feature_names[i], self.feature_importance[i]) for i in idx]",
