            codingExamples: "import numpy as np\n\n# Gini impurity calculation\ndef gini_impurity(y):\n    classes, counts = np.unique(y, return_counts=True)\n    probs = counts / len(y)\n    return 1 - np.sum(probs ** 2)\n\ndef entropy(y):\n    classes, counts = np.unique(y, return_counts=True)\n    probs = counts / len(y)\n    return -np.sum(probs * np.log2(probs + 1e-9))\n\ndef information_gain(y, y_left, y_right):\n    \\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"Information gain from a split\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\",\n    parent_impurity = gini_impurity(y)\n    n = len(y)\n    n_l, n_r = len(y_left), len(y_right)\n    child_impurity = (n_l/n) * gini_impurity(y_left) + (n_r/n) * gini_impurity(y_right)\n    return parent_impurity - child_impurity\n\n# Example\ny = np.array([0, 0, 0, 1, 1, 1])\ny_left = np.array([0, 0, 0])\ny_right = np.array([1, 1, 1])\nprint(f'IG of perfect split: {information_gain(y, y_left, y_right):.3f}')\n# 0.5 - perfectly splits the data",
