            productionExample: "import numpy as np\nfrom sklearn.ensemble import RandomForestClassifier\nimport joblib\n\nclass RandomForestPipeline:\n    def __init__(self, n_estimators=200, max_depth=15):\n        self.model = RandomForestClassifier(\n            n_estimators=n_estimators,\n            max_depth=max_depth,\n            min_samples_leaf=5,\n            oob_score=True,\n            n_jobs=-1,\n            random_state=42\n        )\n\n    def fit(self, X, y):\n        self.model.fit(X, y)\n        self.oob_score = self.model.oob_score_\n        self.feature_importance = self.model.feature_importances_\n        return self\n\n    def predict(self, X):\n        return self.model.predict(X)\n\n    def predict_proba(self, X):\n        return self.model.predict_proba(X)\n\n    def partial_dependence(self, X, feature_idx):\n        \\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"Compute partial dependence for model interpretation\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\",\n        values = np.linspace(X[:, feature_idx].min(), X[:, feature_idx].max(), 50)\n        pd_values = []\n        for v in values:\n            X_perturbed = X.copy()\n            X_perturbed[:, feature_idx] = v\n            pd_values.append(self.model.predict_proba(X_perturbed)[:, 1].mean())\n        return values, np.array(pd_values)\n\n    def save(self, path):\n        joblib.dump(self.model, path)\n\n    @classmethod\n    def load(cls, path):\n        instance = cls()\n        instance.model = joblib.load(path)\n        return instance",
