            codingExamples: "import numpy as np\nfrom sklearn.ensemble import RandomForestClassifier\n\n# Feature importance analysis\ndef plot_feature_importance(model, feature_names):\n    importances = model.feature_importances_\n    indices = np.argsort(importances)[::-1]\n    print('Feature ranking:')\n    for i in range(min(10, len(feature_names))):\n        print(f'  {i+1}. {feature_names[indices[i]]} ({importances[indices[i]]:.3f})')\n\n# Out-of-bag scoring\nrf = RandomForestClassifier(n_estimators=100, oob_score=True)\nrf.fit(X, y)\nprint(f'OOB accuracy: {rf.oob_score_:.3f}')\n\n# Proximity matrix (how often pairs end up in same leaf)\ndef proximity_matrix(model, X):\n    \\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"Compute Random Forest proximity matrix\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\",\n    n_samples = X.shape[0]\n    prox = np.zeros((n_samples, n_samples))\n    for tree in model.estimators_:\n        leaves = tree.apply(X)\n        for i in range(n_samples):\n            for j in range(i + 1, n_samples):\n                if leaves[i] == leaves[j]:\n                    prox[i, j] += 1\n                    prox[j, i] += 1\n    return prox / len(model.estimators_)",
