            codingExamples: "import numpy as np\nfrom sklearn.model_selection import learning_curve\n\n# Learning curve for bias-variance diagnosis\ndef plot_learning_curve(estimator, X, y, cv=5):\n    train_sizes, train_scores, test_scores = learning_curve(\n        estimator, X, y, cv=cv, n_jobs=-1,\n        train_sizes=np.linspace(0.1, 1.0, 10),\n        scoring='neg_mean_squared_error'\n    )\n    train_errors = -train_scores\n    test_errors = -test_scores\n    \n    train_mean = np.mean(train_errors, axis=1)\n    test_mean = np.mean(test_errors, axis=1)\n    train_std = np.std(train_errors, axis=1)\n    test_std = np.std(test_errors, axis=1)\n    \n    print('Train size | Train MSE | Test MSE | Gap')\n    for i, n in enumerate(train_sizes):\n        gap = test_mean[i] - train_mean[i]\n        print(f'{n:9d} | {train_mean[i]:.3f} | {test_mean[i]:.3f} | {gap:.3f}')\n    \n    # Diagnosis\n    final_gap = test_mean[-1] - train_mean[-1]\n    final_test = test_mean[-1]\n    if final_gap > 0.2 * final_test:\n        print('Diagnosis: High Variance (overfitting)')\n    elif final_test > 0.5:\n        print('Diagnosis: High Bias (underfitting)')\n    else:\n        print('Diagnosis: Good fit')",
