            intermediateExample: "import numpy as np\nfrom sklearn.naive_bayes import MultinomialNB, ComplementNB\nfrom sklearn.feature_extraction.text import CountVectorizer\nfrom sklearn.model_selection import cross_val_score\n\n# Text classification with MultinomialNB\ncorpus = [\n    'free money now!!!',  # spam\n    'win a prize today',  # spam\n    'meeting at 3pm tomorrow',  # ham\n    'please review the attached document',  # ham\n    'congratulations you won',  # spam\n    'project deadline next week',  # ham\n]\nlabels = [1, 1, 0, 0, 1, 0]\n\nvectorizer = CountVectorizer()\nX = vectorizer.fit_transform(corpus)\n\nmnb = MultinomialNB(alpha=1.0)\nscores = cross_val_score(mnb, X, labels, cv=3)\nprint(f'CV accuracy: {scores.mean():.3f}')\n\n# ComplementNB (better for imbalanced data)\ncnb = ComplementNB()\nscores_cnb = cross_val_score(cnb, X, labels, cv=3)\nprint(f'ComplementNB accuracy: {scores_cnb.mean():.3f}')",
            productionExample: "import numpy as np\nfrom sklearn.naive_bayes import MultinomialNB\nfrom sklearn.feature_extraction.text import TfidfVectorizer\nfrom sklearn.pipeline import Pipeline\n\nclass TextClassifier:\n    def __init__(self, alpha=1.0):\n        self.pipeline = Pipeline([\n            ('vectorizer', TfidfVectorizer(max_features=10000, stop_words='english')),\n            ('classifier', MultinomialNB(alpha=alpha))\n        ])\n\n    def fit(self, texts, labels):\n        self.pipeline.fit(texts, labels)\n        return self\n\n    def predict(self, texts):\n        return self.pipeline.predict(texts)\n\n    def predict_proba(self, texts):\n        return self.pipeline.predict_proba(texts)\n\n    def most_informative_features(self, n=10):\n        \\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"Top n features per class by log-probability ratio\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\",\n        feature_names = self.pipeline.named_steps['vectorizer'].get_feature_names_out()\n        class_log_probs = self.pipeline.named_steps['classifier'].feature_log_prob_\n        for i, class_probs in enumerate(class_log_probs):\n            top_idx = np.argsort(class_probs)[-n:][::-1]\n            print(f'Class {i} top features:')\n            for idx in top_idx:\n                print(f'  {feature_names[idx]}: {np.exp(class_probs[idx]):.4f}')\n        return self",
            industryScenario: "At Google, Naive Bayes filters billions of spam emails daily. The model uses millions of features (words, sender patterns, metadata). Despite its simplicity, MultinomialNB's speed (milliseconds per email) and simplicity make it practical at Google's scale. It catches >99.9% of spam.",
