            productionExample: "import numpy as np\n\n# Numerically stable sigmoid\ndef stable_sigmoid(z):\n    \\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"Numerically stable sigmoid for large positive/negative values\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\",\n    return np.where(z >= 0,\n                    1 / (1 + np.exp(-z)),\n                    np.exp(z) / (1 + np.exp(z)))\n\n# Softmax for multi-class (generalization of sigmoid)\ndef softmax(z):\n    \\\"\\\"\\\"Multi-class generalization of sigmoid\\\"\\\"\\\"\n    exp_z = np.exp(z - np.max(z, axis=-1, keepdims=True))\n    return exp_z / np.sum(exp_z, axis=-1, keepdims=True)\n\n# Log-sum-exp trick for numerical stability\ndef log_sigmoid(z):\n    \\\"\\\"\\\"Log of sigmoid, numerically stable\\\"\\\"\\\"\n    return -np.log1p(np.exp(-np.abs(z))) - np.maximum(-z, 0)\n\n# Binary cross-entropy with sigmoid (combined for stability)\ndef binary_cross_entropy(y_true, logits):\n    \\\"\\\"\\\"Compute BCE directly from logits for numerical stability\\\"\\\"\\\"\n    return np.mean(np.maximum(logits, 0) - logits * y_true + np.log1p(np.exp(-np.abs(logits))))",
