            codingExamples: "import numpy as np\n\n# Sigmoid variants\ndef sigmoid_basic(z):\n    return 1 / (1 + np.exp(-z))\n\ndef sigmoid_stable(z):\n    \\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"Avoid overflow for large negative z\\\\\\\\\\\\\\\"\\\\\\\\\\\\\\\"\\\\\\\\\",\n    return np.where(z >= 0, 1/(1+np.exp(-z)), np.exp(z)/(1+np.exp(z)))\n\n# Verify stability\nlarge_negative = -1000\nprint(f'Basic: {sigmoid_basic(large_negative)}')  # May overflow\nprint(f'Stable: {sigmoid_stable(large_negative)}')  # 0.0\n\n# Gradient of sigmoid\ndef sigmoid_gradient(z):\n    s = sigmoid_stable(z)\n    return s * (1 - s)\n\n# Logit (inverse of sigmoid)\ndef logit(p):\n    \\\"\\\"\\\"Inverse of sigmoid: maps probability back to real space\\\"\\\"\\\"\n    p = np.clip(p, 1e-15, 1 - 1e-15)\n    return np.log(p / (1 - p))",
